sql:
SELECT project_id
FROM sprints
WHERE sprint_name = 'Sprint 1';

SELECT COUNT(team_member_name) 
FROM team_members 
WHERE role = 'Developer' AND availability = 'Full-time';

external_knowledge:
- 'Steelfast pillars' metaphorically refers to team members marked as 'Full-time', signifying their critical role and consistent presence in the organization;
- 'Identities and characteristics' encompass the team member ID, name, email, role, department, project ID, creation and update details, expertise, and availability;
- 'The hands that sowed the seeds of their presence' and 'the guardians of their records' are metaphors for the users who created and last updated the records of the team members, respectively.

sql:
SELECT project_id, COUNT(*) AS number_of_sprints 
FROM sprints 
GROUP BY project_id;

SELECT user_story_title
FROM user_stories
WHERE status = 'In Progress';

SELECT DISTINCT tm.team_member_name AS AssignedTeamMembers
FROM tasks t
JOIN team_members tm ON t.assigned_to = tm.team_member_id;

SELECT SUM(story_points) 
FROM user_stories 
WHERE priority = 'High';

SELECT user_story_title 
FROM user_stories 
WHERE user_story_id = 'specific_user_story_id';

SELECT AVG(story_points) AS average_story_points
FROM user_stories
WHERE sprint_id = 0 AND status = 'In Progress';
